     6→// This file implements checkpoint persistence for the in-memory metric store.
     7→//
     8→// Checkpoints enable graceful restarts by periodically saving in-memory metric
     9→// data to disk in JSON or binary format. The checkpoint system:
    10→//
    11→// Key Features:
    12→//   - Periodic background checkpointing via the Checkpointing() worker
    13→//   - Two format families: JSON (human-readable) and WAL+binary (compact, crash-safe)
    14→//   - Parallel checkpoint creation and loading using worker pools
    15→//   - Hierarchical file organization: checkpoint_dir/cluster/host/timestamp.{json|bin}
    16→//   - WAL file: checkpoint_dir/cluster/host/current.wal (append-only, per-entry)
    17→//   - Only saves unarchived data (archived data is already persisted elsewhere)
    18→//   - GC optimization during loading to prevent excessive heap growth
    19→//
    20→// Checkpoint Workflow:
    21→//  1. Init() loads checkpoints within retention window at startup
    22→//  2. Checkpointing() worker periodically saves new data
    23→//  3. Shutdown() writes final checkpoint before exit
    24→//
    25→// File Organization:
    26→//
    27→//	checkpoints/
    28→//	  cluster1/
    29→//	    host001/
    30→//	      1234567890.json  (JSON format: full subtree snapshot)
    31→//	      1234567890.bin   (binary format: full subtree snapshot)
    32→//	      current.wal      (WAL format: append-only per-entry log)
    33→//	    host002/
    34→//	      ...
    35→package metricstore
    36→
    37→import (
    38→	"bufio"
    39→	"context"
    40→	"encoding/json"
    41→	"errors"
    42→	"fmt"
    43→	"io/fs"
    44→	"os"
    45→	"path"
    46→	"path/filepath"
    47→	"sort"
    48→	"strconv"
    49→	"strings"
    50→	"sync"
    51→	"sync/atomic"
    52→	"time"
    53→
    54→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
    55→	"github.com/ClusterCockpit/cc-lib/v2/schema"
    56→)
    57→
    58→const (
    59→	CheckpointFilePerms = 0o644                    // File permissions for checkpoint files
    60→	CheckpointDirPerms  = 0o755                    // Directory permissions for checkpoint directories
    61→	GCTriggerInterval   = DefaultGCTriggerInterval // Interval for triggering GC during checkpoint loading
    62→)
    63→
    64→// CheckpointMetrics represents metric data in a checkpoint file.
    65→// Whenever the structure changes, update MarshalJSON as well!
    66→type CheckpointMetrics struct {
    67→	Data      []schema.Float `json:"data"`
    68→	Frequency int64          `json:"frequency"`
    69→	Start     int64          `json:"start"`
    70→}
    71→
    72→// CheckpointFile represents the hierarchical structure of a checkpoint file.
    73→// It mirrors the Level tree structure from the MemoryStore.
    74→type CheckpointFile struct {
    75→	Metrics  map[string]*CheckpointMetrics `json:"metrics"`
    76→	Children map[string]*CheckpointFile    `json:"children"`
    77→	From     int64                         `json:"from"`
    78→	To       int64                         `json:"to"`
    79→}
    80→
    81→// lastCheckpoint tracks the timestamp of the last checkpoint creation.
    82→var (
    83→	lastCheckpoint   time.Time
    84→	lastCheckpointMu sync.Mutex
    85→)
    86→
    87→// Checkpointing starts a background worker that periodically saves metric data to disk.
    88→//
    89→// Checkpoints are written every 12 hours (hardcoded).
    90→//
    91→// Format behaviour:
    92→//   - "json": Periodic checkpointing every checkpointInterval
    93→//   - "wal":  Periodic binary snapshots + WAL rotation every checkpointInterval
    94→func Checkpointing(wg *sync.WaitGroup, ctx context.Context) {
    95→	lastCheckpointMu.Lock()
    96→	lastCheckpoint = time.Now()
    97→	lastCheckpointMu.Unlock()
    98→
    99→	ms := GetMemoryStore()
   100→
   101→	wg.Go(func() {
   102→
   103→		d := 12 * time.Hour // default checkpoint interval
   104→		if Keys.CheckpointInterval != "" {
   105→			parsed, err := time.ParseDuration(Keys.CheckpointInterval)
   106→			if err != nil {
   107→				cclog.Errorf("[METRICSTORE]> invalid checkpoint-interval %q: %s, using default 12h", Keys.CheckpointInterval, err)
   108→			} else {
   109→				d = parsed
   110→			}
   111→		}
   112→
   113→		ticker := time.NewTicker(d)
   114→		defer ticker.Stop()
   115→
   116→		for {
   117→			select {
   118→			case <-ctx.Done():
   119→				return
   120→			case <-ticker.C:
   121→				lastCheckpointMu.Lock()
   122→				from := lastCheckpoint
   123→				lastCheckpointMu.Unlock()
   124→
   125→				now := time.Now()
   126→				cclog.Infof("[METRICSTORE]> start checkpointing (starting at %s)...", from.Format(time.RFC3339))
   127→
   128→				if Keys.Checkpoints.FileFormat == "wal" {
   129→					// Pause WAL writes: the binary snapshot captures all in-memory
   130→					// data, so WAL records written during checkpoint are redundant
   131→					// and would be deleted during rotation anyway.
   132→					walCheckpointActive.Store(true)
   133→					n, hostDirs, err := ms.ToCheckpointWAL(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
   134→					if err != nil {
   135→						cclog.Errorf("[METRICSTORE]> binary checkpointing failed: %s", err.Error())
   136→					}
   137→					if n > 0 {
   138→						cclog.Infof("[METRICSTORE]> done: %d binary snapshot files created", n)
   139→						lastCheckpointMu.Lock()
   140→						lastCheckpoint = now
   141→						lastCheckpointMu.Unlock()
   142→						// Rotate WAL files for successfully checkpointed hosts.
   143→						RotateWALFiles(hostDirs)
   144→					}
   145→					walCheckpointActive.Store(false)
   146→					walDropped.Store(0)
   147→				} else {
   148→					n, err := ms.ToCheckpoint(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
   149→					if err != nil {
   150→						cclog.Errorf("[METRICSTORE]> checkpointing failed: %s", err.Error())
   151→					} else {
   152→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files created", n)
   153→						lastCheckpointMu.Lock()
   154→						lastCheckpoint = now
   155→						lastCheckpointMu.Unlock()
   156→					}
   157→				}
   158→			}
   159→		}
   160→	})
   161→}
   162→
   163→// MarshalJSON provides optimized JSON encoding for CheckpointMetrics.
   164→//
   165→// Since schema.Float has custom MarshalJSON, serializing []Float has significant overhead.
   166→// This method manually constructs JSON to avoid allocations and interface conversions.
   167→func (cm *CheckpointMetrics) MarshalJSON() ([]byte, error) {
   168→	buf := make([]byte, 0, 128+len(cm.Data)*8)
   169→	buf = append(buf, `{"frequency":`...)
   170→	buf = strconv.AppendInt(buf, cm.Frequency, 10)
   171→	buf = append(buf, `,"start":`...)
   172→	buf = strconv.AppendInt(buf, cm.Start, 10)
   173→	buf = append(buf, `,"data":[`...)
   174→	for i, x := range cm.Data {
   175→		if i != 0 {
   176→			buf = append(buf, ',')
   177→		}
   178→		if x.IsNaN() {
   179→			buf = append(buf, `null`...)
   180→		} else {
   181→			buf = strconv.AppendFloat(buf, float64(x), 'f', 1, 32)
   182→		}
   183→	}
   184→	buf = append(buf, `]}`...)
   185→	return buf, nil
   186→}
   187→
   188→// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
   189→//
   190→// Metrics at root and cluster levels are skipped. One file per host is created.
   191→// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
   192→// at a time, allowing concurrent writes/reads to other hosts.
   193→//
   194→// Returns the number of checkpoint files created and any errors encountered.
   195→func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
   196→	// Pre-calculate capacity by counting cluster/host pairs
   197→	m.root.lock.RLock()
   198→	totalHosts := 0
   199→	for _, l1 := range m.root.children {
   200→		l1.lock.RLock()
   201→		totalHosts += len(l1.children)
   202→		l1.lock.RUnlock()
   203→	}
   204→	m.root.lock.RUnlock()
   205→
   206→	levels := make([]*Level, 0, totalHosts)
   207→	selectors := make([][]string, 0, totalHosts)
   208→
   209→	m.root.lock.RLock()
   210→	for sel1, l1 := range m.root.children {
   211→		l1.lock.RLock()
   212→		for sel2, l2 := range l1.children {
   213→			levels = append(levels, l2)
   214→			selectors = append(selectors, []string{sel1, sel2})
   215→		}
   216→		l1.lock.RUnlock()
   217→	}
   218→	m.root.lock.RUnlock()
   219→
   220→	type workItem struct {
   221→		level    *Level
   222→		dir      string
   223→		selector []string
   224→	}
   225→
   226→	n, errs := int32(0), int32(0)
   227→
   228→	var wg sync.WaitGroup
   229→	wg.Add(Keys.NumWorkers)
   230→	work := make(chan workItem, Keys.NumWorkers*2)
   231→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   232→		go func() {
   233→			defer wg.Done()
   234→
   235→			for workItem := range work {
   236→				if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
   237→					if err == ErrNoNewArchiveData {
   238→						continue
   239→					}
   240→
   241→					cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
   242→					atomic.AddInt32(&errs, 1)
   243→				} else {
   244→					atomic.AddInt32(&n, 1)
   245→				}
   246→			}
   247→		}()
   248→	}
   249→
   250→	for i := 0; i < len(levels); i++ {
   251→		dir := path.Join(dir, path.Join(selectors[i]...))
   252→		work <- workItem{
   253→			level:    levels[i],
   254→			dir:      dir,
   255→			selector: selectors[i],
   256→		}
   257→	}
   258→
   259→	close(work)
   260→	wg.Wait()
   261→
   262→	if errs > 0 {
   263→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
   264→	}
   265→	return int(n), nil
   266→}
   267→
   268→// toCheckpointFile recursively converts a Level tree to CheckpointFile structure.
   269→// Skips metrics that are already archived. Returns nil if no unarchived data exists.
   270→func (l *Level) toCheckpointFile(from, to int64, m *MemoryStore) (*CheckpointFile, error) {
   271→	l.lock.RLock()
   272→	defer l.lock.RUnlock()
   273→
   274→	retval := &CheckpointFile{
   275→		From:     from,
   276→		To:       to,
   277→		Metrics:  make(map[string]*CheckpointMetrics),
   278→		Children: make(map[string]*CheckpointFile),
   279→	}
   280→
   281→	for metric, minfo := range m.Metrics {
   282→		b := l.metrics[minfo.offset]
   283→		if b == nil {
   284→			continue
   285→		}
   286→
   287→		allArchived := true
   288→		b.iterFromTo(from, to, func(b *buffer) error {
   289→			if !b.archived {
   290→				allArchived = false
   291→				return fmt.Errorf("stop") // Early termination signal
   292→			}
   293→			return nil
   294→		})
   295→
   296→		if allArchived {
   297→			continue
   298→		}
   299→
   300→		data := make([]schema.Float, (to-from)/b.frequency+1)
   301→		data, start, end, err := b.read(from, to, data)
   302→		if err != nil {
   303→			return nil, err
   304→		}
   305→
   306→		for i := int((end - start) / b.frequency); i < len(data); i++ {
   307→			data[i] = schema.NaN
   308→		}
   309→
   310→		retval.Metrics[metric] = &CheckpointMetrics{
   311→			Frequency: b.frequency,
   312→			Start:     start,
   313→			Data:      data,
   314→		}
   315→	}
   316→
   317→	for name, child := range l.children {
   318→		val, err := child.toCheckpointFile(from, to, m)
   319→		if err != nil {
   320→			return nil, err
   321→		}
   322→
   323→		if val != nil {
   324→			retval.Children[name] = val
   325→		}
   326→	}
   327→
   328→	if len(retval.Children) == 0 && len(retval.Metrics) == 0 {
   329→		return nil, nil
   330→	}
   331→
   332→	return retval, nil
   333→}
   334→
   335→// toCheckpoint writes a Level's data to a JSON checkpoint file.
   336→// Creates directory if needed. Returns ErrNoNewArchiveData if nothing to save.
   337→func (l *Level) toCheckpoint(dir string, from, to int64, m *MemoryStore) error {
   338→	cf, err := l.toCheckpointFile(from, to, m)
   339→	if err != nil {
   340→		return err
   341→	}
   342→
   343→	if cf == nil {
   344→		return ErrNoNewArchiveData
   345→	}
   346→
   347→	filepath := path.Join(dir, fmt.Sprintf("%d.json", from))
   348→	f, err := os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   349→	if err != nil && os.IsNotExist(err) {
   350→		err = os.MkdirAll(dir, CheckpointDirPerms)
   351→		if err == nil {
   352→			f, err = os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   353→		}
   354→	}
   355→	if err != nil {
   356→		return err
   357→	}
   358→	defer f.Close()
   359→
   360→	bw := bufio.NewWriter(f)
   361→	if err = json.NewEncoder(bw).Encode(cf); err != nil {
   362→		return err
   363→	}
   364→
   365→	return bw.Flush()
   366→}
   367→
   368→// enqueueCheckpointHosts traverses checkpoint directory and enqueues cluster/host pairs.
   369→// Returns error if directory structure is invalid.
   370→func enqueueCheckpointHosts(dir string, work chan<- [2]string) error {
   371→	clustersDir, err := os.ReadDir(dir)
   372→	if err != nil {
   373→		return err
   374→	}
   375→
   376→	for _, clusterDir := range clustersDir {
   377→		if !clusterDir.IsDir() {
   378→			return errors.New("[METRICSTORE]> expected only directories at first level of checkpoints/ directory")
   379→		}
   380→
   381→		hostsDir, err := os.ReadDir(filepath.Join(dir, clusterDir.Name()))
   382→		if err != nil {
   383→			return err
   384→		}
   385→
   386→		for _, hostDir := range hostsDir {
   387→			if !hostDir.IsDir() {
   388→				return errors.New("[METRICSTORE]> expected only directories at second level of checkpoints/ directory")
   389→			}
   390→
   391→			work <- [2]string{clusterDir.Name(), hostDir.Name()}
   392→		}
   393→	}
   394→
   395→	return nil
   396→}
   397→
   398→// FromCheckpoint loads checkpoint files from disk into memory in parallel.
   399→//
   400→// Uses worker pool to load cluster/host combinations. Returns number of files
   401→// loaded and any errors.
   402→func (m *MemoryStore) FromCheckpoint(dir string, from int64) (int, error) {
   403→	var wg sync.WaitGroup
   404→	work := make(chan [2]string, Keys.NumWorkers*4)
   405→	n, errs := int32(0), int32(0)
   406→
   407→	wg.Add(Keys.NumWorkers)
   408→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   409→		go func() {
   410→			defer wg.Done()
   411→			for host := range work {
   412→				lvl := m.root.findLevelOrCreate(host[:], len(m.Metrics))
   413→				nn, err := lvl.fromCheckpoint(m, filepath.Join(dir, host[0], host[1]), from)
   414→				if err != nil {
   415→					cclog.Errorf("[METRICSTORE]> error while loading checkpoints for %s/%s: %s", host[0], host[1], err.Error())
   416→					atomic.AddInt32(&errs, 1)
   417→				}
   418→				atomic.AddInt32(&n, int32(nn))
   419→			}
   420→		}()
   421→	}
   422→
   423→	err := enqueueCheckpointHosts(dir, work)
   424→	close(work)
   425→	wg.Wait()
   426→
   427→	if err != nil {
   428→		return int(n), err
   429→	}
   430→
   431→	if errs > 0 {
   432→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
   433→	}
   434→	return int(n), nil
   435→}
   436→
   437→// FromCheckpointFiles is the main entry point for loading checkpoints at startup.
   438→//
   439→// Creates checkpoint directory if it doesn't exist. This function must be called
   440→// before any writes or reads, and can only be called once.
   441→func (m *MemoryStore) FromCheckpointFiles(dir string, from int64) (int, error) {
   442→	if _, err := os.Stat(dir); os.IsNotExist(err) {
   443→		err := os.MkdirAll(dir, CheckpointDirPerms)
   444→		if err != nil {
   445→			cclog.Fatalf("[METRICSTORE]> Error creating directory: %#v\n", err)
   446→		}
   447→		cclog.Debugf("[METRICSTORE]> %#v Directory created successfully", dir)
   448→	}
   449→
   450→	return m.FromCheckpoint(dir, from)
   451→}
   452→
   453→func (l *Level) loadJSONFile(m *MemoryStore, f *os.File, from int64) error {
   454→	br := bufio.NewReader(f)
   455→	cf := &CheckpointFile{}
   456→	if err := json.NewDecoder(br).Decode(cf); err != nil {
   457→		return err
   458→	}
   459→
   460→	if cf.To != 0 && cf.To < from {
   461→		return nil
   462→	}
   463→
   464→	if err := l.loadFile(cf, m); err != nil {
   465→		return err
   466→	}
   467→
   468→	return nil
   469→}
   470→
   471→func (l *Level) loadFile(cf *CheckpointFile, m *MemoryStore) error {
   472→	for name, metric := range cf.Metrics {
   473→		n := len(metric.Data)
   474→		b := &buffer{
   475→			frequency: metric.Frequency,
   476→			start:     metric.Start,
   477→			data:      metric.Data[0:n:n],
   478→			prev:      nil,
   479→			next:      nil,
   480→			archived:  true,
   481→		}
   482→
   483→		minfo, ok := m.Metrics[name]
   484→		if !ok {
   485→			continue
   486→		}
   487→
   488→		prev := l.metrics[minfo.offset]
   489→		if prev == nil {
   490→			l.metrics[minfo.offset] = b
   491→		} else {
   492→			if prev.start > b.start {
   493→				return fmt.Errorf("[METRICSTORE]> buffer start time %d is before previous buffer start %d", b.start, prev.start)
   494→			}
   495→
   496→			b.prev = prev
   497→			prev.next = b
   498→		}
   499→		l.metrics[minfo.offset] = b
   500→	}
   501→
   502→	if len(cf.Children) > 0 && l.children == nil {
   503→		l.children = make(map[string]*Level)
   504→	}
   505→
   506→	for sel, childCf := range cf.Children {
   507→		child, ok := l.children[sel]
   508→		if !ok {
   509→			child = &Level{
   510→				metrics:  make([]*buffer, len(m.Metrics)),
   511→				children: nil,
   512→			}
   513→			l.children[sel] = child
   514→		}
   515→
   516→		if err := child.loadFile(childCf, m); err != nil {
   517→			return err
   518→		}
   519→	}
   520→
   521→	return nil
   522→}
   523→
   524→// fromCheckpoint loads all checkpoint files (JSON, binary snapshot, WAL) for a
   525→// single host directory. Snapshot files are loaded first (sorted by timestamp),
   526→// then current.wal is replayed on top.
   527→func (l *Level) fromCheckpoint(m *MemoryStore, dir string, from int64) (int, error) {
   528→	direntries, err := os.ReadDir(dir)
   529→	if err != nil {
   530→		if os.IsNotExist(err) {
   531→			return 0, nil
   532→		}
   533→		return 0, err
   534→	}
   535→
   536→	allFiles := make([]fs.DirEntry, 0)
   537→	var walEntry fs.DirEntry
   538→	filesLoaded := 0
   539→
   540→	for _, e := range direntries {
   541→		if e.IsDir() {
   542→			// Legacy: skip subdirectories (only used by old Avro format).
   543→			// These are ignored; their data is not loaded.
   544→			cclog.Debugf("[METRICSTORE]> skipping subdirectory %s in checkpoint dir %s", e.Name(), dir)
   545→			continue
   546→		}
   547→
   548→		name := e.Name()
   549→		if strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".bin") {
   550→			allFiles = append(allFiles, e)
   551→		} else if name == "current.wal" {
   552→			walEntry = e
   553→		}
   554→		// Silently ignore other files (e.g., .tmp, .bin.tmp from interrupted writes).
   555→	}
   556→
   557→	files, err := findFiles(allFiles, from, true)
   558→	if err != nil {
   559→		return filesLoaded, err
   560→	}
   561→
   562→	loaders := map[string]func(*MemoryStore, *os.File, int64) error{
   563→		".json": l.loadJSONFile,
   564→		".bin":  l.loadBinaryFile,
   565→	}
   566→
   567→	for _, filename := range files {
   568→		ext := filepath.Ext(filename)
   569→		loader := loaders[ext]
   570→		if loader == nil {
   571→			cclog.Warnf("[METRICSTORE]> unknown extension for checkpoint file %s", filename)
   572→			continue
   573→		}
   574→
   575→		err := func() error {
   576→			f, err := os.Open(path.Join(dir, filename))
   577→			if err != nil {
   578→				return err
   579→			}
   580→			defer f.Close()
   581→			return loader(m, f, from)
   582→		}()
   583→		if err != nil {
   584→			return filesLoaded, err
   585→		}
   586→		filesLoaded++
   587→	}
   588→
   589→	// Replay WAL after all snapshot files so it fills in data since the last snapshot.
   590→	if walEntry != nil {
   591→		err := func() error {
   592→			f, err := os.Open(path.Join(dir, walEntry.Name()))
   593→			if err != nil {
   594→				return err
   595→			}
   596→			defer f.Close()
   597→			return l.loadWALFile(m, f, from)
   598→		}()
   599→		if err != nil {
   600→			// WAL errors are non-fatal: the snapshot already loaded the bulk of data.
   601→			cclog.Warnf("[METRICSTORE]> WAL replay error for %s: %v (data since last snapshot may be missing)", dir, err)
   602→		} else {
   603→			filesLoaded++
   604→		}
   605→	}
   606→
   607→	return filesLoaded, nil
   608→}
   609→
   610→// parseTimestampFromFilename extracts a Unix timestamp from a checkpoint filename.
   611→// Supports ".json" (format: "<ts>.json") and ".bin" (format: "<ts>.bin").
   612→func parseTimestampFromFilename(name string) (int64, error) {
   613→	switch {
   614→	case strings.HasSuffix(name, ".json"):
   615→		return strconv.ParseInt(name[:len(name)-5], 10, 64)
   616→	case strings.HasSuffix(name, ".bin"):
   617→		return strconv.ParseInt(name[:len(name)-4], 10, 64)
   618→	default:
   619→		return 0, fmt.Errorf("unknown checkpoint extension for file %q", name)
   620→	}
   621→}
   622→
   623→// findFiles returns filenames from direntries whose timestamps satisfy the filter.
   624→// If findMoreRecentFiles is true, returns files with timestamps >= t (plus the
   625→// last file before t if t falls between two files).
   626→func findFiles(direntries []fs.DirEntry, t int64, findMoreRecentFiles bool) ([]string, error) {
   627→	nums := map[string]int64{}
   628→	for _, e := range direntries {
   629→		name := e.Name()
   630→		if !strings.HasSuffix(name, ".json") && !strings.HasSuffix(name, ".bin") {
   631→			continue
   632→		}
   633→
   634→		ts, err := parseTimestampFromFilename(name)
   635→		if err != nil {
   636→			return nil, err
   637→		}
   638→		nums[name] = ts
   639→	}
   640→
   641→	sort.Slice(direntries, func(i, j int) bool {
   642→		a, b := direntries[i], direntries[j]
   643→		return nums[a.Name()] < nums[b.Name()]
   644→	})
   645→
   646→	if len(nums) == 0 {
   647→		return nil, nil
   648→	}
   649→
   650→	filenames := make([]string, 0)
   651→
   652→	for i, e := range direntries {
   653→		ts1 := nums[e.Name()]
   654→
   655→		if findMoreRecentFiles && t <= ts1 {
   656→			filenames = append(filenames, e.Name())
   657→		} else if !findMoreRecentFiles && ts1 <= t && ts1 != 0 {
   658→			filenames = append(filenames, e.Name())
   659→		}
   660→
   661→		if i == len(direntries)-1 {
   662→			continue
   663→		}
   664→
   665→		enext := direntries[i+1]
   666→		ts2 := nums[enext.Name()]
   667→
   668→		if findMoreRecentFiles {
   669→			if ts1 < t && t < ts2 {
   670→				filenames = append(filenames, e.Name())
   671→			}
   672→		}
   673→	}
   674→
   675→	return filenames, nil
   676→}
   677→

